import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, Handshake, CheckCircle, Clock, Check, X } from 'lucide-react';

export default function BarterRequest() {
  const [requests, setRequests] = useState([]);
  const [isSent, setIsSent] = useState(false);
  const currentUser = "Gouri"; // This represents you

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem('wertech_barters') || '[]');
    setRequests(saved);
  }, []);

  const handleSend = (e) => {
    e.preventDefault();
    const formData = new FormData(e.target);
    const newRequest = {
      id: Date.now(),
      sender: currentUser,
      receiver: formData.get('receiver'),
      item: formData.get('item'),
      message: formData.get('message'),
      status: 'Pending',
      time: new Date().toLocaleDateString()
    };

    const updated = [newRequest, ...requests];
    setRequests(updated);
    localStorage.setItem('wertech_barters', JSON.stringify(updated));
    setIsSent(true);
    e.target.reset();
    setTimeout(() => setIsSent(false), 3000);
  };

  const updateStatus = (id, newStatus) => {
    const updated = requests.map(req => 
      req.id === id ? { ...req, status: newStatus } : req
    );
    setRequests(updated);
    localStorage.setItem('wertech_barters', JSON.stringify(updated));
  };

  return (
    <div className="p-10 max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-12">
      
      {/* FORM SECTION (Left Side) */}
      <div className="lg:col-span-5 bg-white dark:bg-slate-900 rounded-[40px] p-10 shadow-sm border border-slate-100 dark:border-slate-800 h-fit">
        <div className="flex items-center gap-4 mb-10">
          <div className="p-4 bg-teal-50 dark:bg-teal-900/30 text-teal-600 rounded-3xl">
            <Handshake size={32} />
          </div>
          <h2 className="text-3xl font-black text-slate-800 dark:text-white">New Barter</h2>
        </div>

        <form onSubmit={handleSend} className="space-y-6">
          <input name="receiver" required placeholder="Recipient (e.g. Rahul K.)" className="w-full p-5 bg-slate-50 dark:bg-slate-800 dark:text-white rounded-[24px] border-none outline-none focus:ring-2 ring-teal-500" />
          <input name="item" required placeholder="Item/Skill you want" className="w-full p-5 bg-slate-50 dark:bg-slate-800 dark:text-white rounded-[24px] border-none outline-none focus:ring-2 ring-teal-500" />
          <textarea name="message" rows="3" placeholder="Your proposal details..." className="w-full p-5 bg-slate-50 dark:bg-slate-800 dark:text-white rounded-[24px] border-none outline-none focus:ring-2 ring-teal-500" />
          <button className="w-full py-5 bg-teal-600 text-white rounded-[24px] font-black text-lg flex items-center justify-center gap-3 shadow-xl hover:bg-teal-700 transition-all active:scale-95">
            Send Request <Send size={20} />
          </button>
        </form>
      </div>

      {/* ACTIVITY SECTION (Right Side) */}
      <div className="lg:col-span-7 space-y-8">
        <h3 className="text-2xl font-black text-slate-800 dark:text-white flex items-center gap-3 ml-2">
          <Clock size={24} className="text-teal-600"/> Request Ledger
        </h3>
        
        <div className="space-y-4 h-[600px] overflow-y-auto pr-2 custom-scrollbar">
          {requests.length === 0 ? (
            <div className="p-20 text-center border-4 border-dashed border-slate-100 dark:border-slate-800 rounded-[40px] text-slate-300 font-bold">
              No barter activity yet.
            </div>
          ) : (
            requests.map(req => {
              const isIncoming = req.receiver === currentUser;
              return (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} key={req.id} className="bg-white dark:bg-slate-900 p-6 rounded-[35px] border border-slate-50 dark:border-slate-800 shadow-sm flex flex-col gap-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black ${isIncoming ? 'bg-amber-100 text-amber-600' : 'bg-teal-100 text-teal-600'}`}>
                        {isIncoming ? "IN" : "OUT"}
                      </div>
                      <div>
                        <h4 className="font-black text-slate-800 dark:text-white uppercase text-xs tracking-widest">
                          {isIncoming ? `From: ${req.sender}` : `To: ${req.receiver}`}
                        </h4>
                        <p className="font-bold text-lg dark:text-slate-300">{req.item}</p>
                      </div>
                    </div>
                    <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                      req.status === 'Accepted' ? 'bg-teal-600 text-white' : 
                      req.status === 'Declined' ? 'bg-red-500 text-white' : 'bg-slate-100 text-slate-500'
                    }`}>
                      {req.status}
                    </span>
                  </div>

                  {/* ACTION BUTTONS (Only show for incoming pending requests) */}
                  {isIncoming && req.status === 'Pending' && (
                    <div className="flex gap-3 pt-2">
                      <button 
                        onClick={() => updateStatus(req.id, 'Accepted')}
                        className="flex-1 py-3 bg-teal-600 text-white rounded-2xl font-black text-xs flex items-center justify-center gap-2 hover:bg-teal-700 transition-all"
                      >
                        <Check size={16} /> Accept
                      </button>
                      <button 
                        onClick={() => updateStatus(req.id, 'Declined')}
                        className="flex-1 py-3 bg-slate-100 text-slate-600 rounded-2xl font-black text-xs flex items-center justify-center gap-2 hover:bg-slate-200 transition-all"
                      >
                        <X size={16} /> Decline
                      </button>
                    </div>
                  )}
                </motion.div>
              );
            })
          )}
        </div>
      </div>

      {/* SUCCESS POPUP */}
      <AnimatePresence>
        {isSent && (
          <motion.div initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: 50, opacity: 0 }} className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-slate-900 text-white px-10 py-5 rounded-full shadow-2xl flex items-center gap-4 z-50">
            <CheckCircle className="text-teal-400" size={24} />
            <span className="font-black uppercase text-xs tracking-widest">Proposal Dispatched</span>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
